import {
	createContext,
	FC,
	ReactNode,
	useCallback,
	useContext,
	useMemo,
	useState,
} from 'react';

export enum Language {
	English = 'en',
	Spanish = 'es',
	French = 'fr',
	German = 'de',
	Italian = 'it',
	Portuguese = 'pt',
	Russian = 'ru',
	ChineseSimplified = 'zh',
	ChineseTraditional = 'zh-TW',
	Japanese = 'ja',
	Korean = 'ko',
	Arabic = 'ar',
	Hindi = 'hi',
	Vietnamese = 'vi',
	Dutch = 'nl',
	Greek = 'el',
	Turkish = 'tr',
	Polish = 'pl',
	Hebrew = 'he',
	Swedish = 'sv',
	Danish = 'da',
	Norwegian = 'no',
	Finnish = 'fi',
	Thai = 'th',
	Indonesian = 'id',
	Malay = 'ms',
	Czech = 'cs',
	Hungarian = 'hu',
	Romanian = 'ro',
	Ukrainian = 'uk',
	Persian = 'fa',
}

type Namespace = Record<string, string>;
type NamespacedTranslations = Record<string, Namespace>;
type LanguageMap = Partial<Record<Language, NamespacedTranslations>>;

interface LanguageContextProps {
	language: Language;
	setLanguage: (lang: Language) => void;
	t: (key: string, fallback?: string) => string;
}

interface LanguageProviderProps {
	children: ReactNode;
	languageMap: LanguageMap;
	defaultLanguage?: Language;
	persist?: boolean;
}

const LanguageContext = createContext<LanguageContextProps | undefined>(
	undefined,
);

const LANGUAGE_STORAGE_KEY = 'app_language';

export const LanguageProvider: FC<LanguageProviderProps> = ({
	children,
	languageMap,
	defaultLanguage = Language.English,
	persist = true,
}) => {
	const getInitialLanguage = (): Language => {
		if (persist && typeof localStorage !== 'undefined') {
			const stored = localStorage.getItem(LANGUAGE_STORAGE_KEY);
			if (stored && stored in Language) return stored as Language;
		}

		const browserLang = navigator.language.split('-')[0] as Language;
		return browserLang in Language ? browserLang : defaultLanguage;
	};

	const [language, setLanguage] = useState<Language>(getInitialLanguage);

	const setLanguageToLocalStorage = (lang: Language) => {
		setLanguage(lang);
		if (persist) localStorage.setItem(LANGUAGE_STORAGE_KEY, lang);
	};

	const translations = useMemo(
		() => languageMap[language] ?? {},
		[language, languageMap],
	);

	const t = useCallback(
		(nsKey: string, key?: string, fallback?: string): string => {
			let ns: string;
			let actualKey: string;

			// Support t("common.greeting") and t("common", "greeting")
			if (key) {
				ns = nsKey;
				actualKey = key;
			} else {
				const parts = nsKey.split('.');
				ns = parts[0];
				actualKey = parts.slice(1).join('.');
			}

			const namespace = translations[ns];
			const value = namespace?.[actualKey];

			if (!value) {
				console.warn(
					`Missing translation for "${ns}.${actualKey}" in language "${language}"`,
				);
			}

			return value ?? fallback ?? actualKey;
		},
		[translations, language],
	);

	const value = useMemo(
		() => ({
			language,
			setLanguage: setLanguageToLocalStorage,
			t,
		}),
		[language, setLanguageToLocalStorage, t],
	);

	return (
		<LanguageContext.Provider value={value}>
			{children}
		</LanguageContext.Provider>
	);
};

export const useLanguage = () => {
	const context = useContext(LanguageContext);
	if (!context)
		throw new Error('useLanguage must be used within a LanguageProvider');
	return context;
};

export const useTranslation = () => {
	const context = useLanguage();
	return context.t;
};

import React, {
	createContext,
	useCallback,
	useContext,
	useMemo,
	useState,
} from 'react';

type ModalContextType = {
	isOpen: boolean;
	modalContent: React.ReactNode | null;
	openModal: (content: React.ReactNode) => void;
	closeModal: () => void;
};

const ModalContext = createContext<ModalContextType | undefined>(undefined);

export const ModalProvider: React.FC<{ children: React.ReactNode }> = ({
	children,
}) => {
	const [isOpen, setIsOpen] = useState(false);
	const [modalContent, setModalContent] = useState<React.ReactNode | null>(
		null,
	);

	const openModal = useCallback((content: React.ReactNode) => {
		setModalContent(content);
		setIsOpen(true);
	}, []);

	const closeModal = useCallback(() => {
		setIsOpen(false);
		setModalContent(null);
	}, []);

	const value = useMemo(
		() => ({ isOpen, modalContent, openModal, closeModal }),
		[isOpen, modalContent, openModal, closeModal],
	);

	return (
		<ModalContext.Provider value={value}>{children}</ModalContext.Provider>
	);
};

export const useModal = (): ModalContextType => {
	const context = useContext(ModalContext);
	if (!context) {
		throw new Error('useModal must be used within a ModalProvider');
	}
	return context;
};

import {
	createContext,
	ReactNode,
	useContext,
	useEffect,
	useMemo,
	useRef,
	useState,
} from 'react';

export enum NotificationType {
	Info = 'info',
	Success = 'success',
	Warning = 'warning',
	Error = 'error',
}

export interface Notification {
	id: string;
	type: NotificationType;
	message: string;
	title?: string;
	dismissible: boolean;
}

interface NotificationContextProps {
	notifications: Notification[];
	addNotification: (
		type: NotificationType,
		message: string,
		options?: {
			title?: string;
			dismissible?: boolean;
			timeout?: number;
		},
	) => string;
	removeNotification: (id: string) => void;
}

const NotificationContext = createContext<NotificationContextProps | undefined>(
	undefined,
);

export const NotificationProvider = ({ children }: { children: ReactNode }) => {
	const [notifications, setNotifications] = useState<Notification[]>([]);
	const timeoutRefs = useRef<Record<string, NodeJS.Timeout>>({});

	useEffect(() => {
		return () => {
			Object.values(timeoutRefs.current).forEach(clearTimeout);
		};
	}, []);

	const removeNotification = (id: string) => {
		setNotifications((prev) => prev.filter((n) => n.id !== id));
		const ref = timeoutRefs.current[id];
		if (ref) {
			clearTimeout(ref);
			delete timeoutRefs.current[id];
		}
	};

	const addNotification = (
		type: NotificationType,
		message: string,
		options?: {
			title?: string;
			dismissible?: boolean;
			timeout?: number;
		},
	): string => {
		const id = crypto.randomUUID();
		const { title, dismissible = true, timeout = 3000 } = options ?? {};

		const notification: Notification = {
			id,
			type,
			message,
			title,
			dismissible,
		};

		setNotifications((prev) => {
			const exists = prev.some((n) => n.message === message && n.type === type);
			return exists ? prev : [...prev, notification];
		});

		timeoutRefs.current[id] = setTimeout(() => {
			removeNotification(id);
		}, timeout);

		return id;
	};

	const value = useMemo(
		() => ({
			notifications,
			addNotification,
			removeNotification,
		}),
		[notifications],
	);

	return (
		<NotificationContext.Provider value={value}>
			{children}
		</NotificationContext.Provider>
	);
};

export const useNotification = (): NotificationContextProps => {
	const context = useContext(NotificationContext);
	if (!context)
		throw new Error(
			'useNotification must be used within a NotificationProvider',
		);
	return context;
};

import React, {
	createContext,
	useState,
	useCallback,
	useMemo,
	useContext,
} from 'react';

type Settings = {
	darkMode: boolean;
	compactMode: boolean;
	language: string;
};

type SettingsContextType = {
	settings: Settings;
	updateSetting: <K extends keyof Settings>(key: K, value: Settings[K]) => void;
	resetSettings: () => void;
};

const defaultSettings: Settings = {
	darkMode: false,
	compactMode: false,
	language: 'en',
};

const SettingsContext = createContext<SettingsContextType | undefined>(
	undefined,
);

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({
	children,
}) => {
	const [settings, setSettings] = useState<Settings>(defaultSettings);

	const updateSetting = useCallback(
		<K extends keyof Settings>(key: K, value: Settings[K]) => {
			setSettings((prev) => ({ ...prev, [key]: value }));
		},
		[],
	);

	const resetSettings = useCallback(() => {
		setSettings(defaultSettings);
	}, []);

	const value = useMemo(
		() => ({ settings, updateSetting, resetSettings }),
		[settings, updateSetting, resetSettings],
	);

	return (
		<SettingsContext.Provider value={value}>
			{children}
		</SettingsContext.Provider>
	);
};

export const useSettings = (): SettingsContextType => {
	const context = useContext(SettingsContext);
	if (!context) {
		throw new Error('useSettings must be used within a SettingsProvider');
	}
	return context;
};

import {
	createContext,
	useContext,
	useEffect,
	useState,
	ReactNode,
	useMemo,
} from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextProps {
	theme: Theme;
	toggleTheme: () => void;
	setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextProps | undefined>(undefined);

export const ThemeProvider = ({ children }: { children: ReactNode }) => {
	const [theme, setTheme] = useState<Theme>('light');

	useEffect(() => {
		const savedTheme = localStorage.getItem('theme') as Theme | null;
		if (savedTheme) {
			setTheme(savedTheme);
		} else {
			const prefersDark = window.matchMedia(
				'(prefers-color-scheme: dark)',
			).matches;
			setTheme(prefersDark ? 'dark' : 'light');
		}
	}, []);

	useEffect(() => {
		document.documentElement.classList.toggle('dark', theme === 'dark');
		localStorage.setItem('theme', theme);
	}, [theme]);

	const toggleTheme = () => {
		setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
	};

	const value = useMemo(() => ({ theme, toggleTheme, setTheme }), [theme]);

	return (
		<ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>
	);
};

export const useTheme = () => {
	const context = useContext(ThemeContext);
	if (!context) throw new Error('useTheme must be used within a ThemeProvider');
	return context;
};

import { trpcClient } from '@start/utils/trpc';
import {
	createContext,
	FC,
	ReactNode,
	useContext,
	useEffect,
	useMemo,
	useState,
} from 'react';

interface User {
	email: string;
}

interface UserContextValue {
	isAuthenticated: boolean;
	isLoading: boolean;
	user: User | null;
	refresh: () => Promise<void>;
	signOut: () => Promise<void>;
}

const UserContext = createContext<UserContextValue | undefined>(undefined);

export const UserProvider: FC<{ children: ReactNode }> = ({
	children,
}: {
	children: ReactNode;
}) => {
	const [
		{ isAuthenticated = false, isLoading = false, user = null },
		setState,
	] = useState<{
		isAuthenticated: boolean;
		isLoading: boolean;
		user: User | null;
	}>({
		isAuthenticated: false,
		isLoading: false,
		user: null,
	});

	const getUser = async () => {
		setState((previous) => ({ ...previous, isLoading: true }));
		try {
			const { user } = await trpcClient.app.user.get.query();
			setState((previous) => ({ ...previous, isAuthenticated: true, user }));
		} catch (err) {
			console.error(err);
			setState((previous) => ({
				...previous,
				isAuthenticated: false,
				user: null,
			}));
		} finally {
			setState((previous) => ({ ...previous, isLoading: false }));
		}
	};

	const signOut = async () => {
		try {
			const { success } = await trpcClient.auth.user.signOut.mutate();
			if (success) {
				alert('Sign Out Successfully');
				setState((previous) => ({
					...previous,
					isAuthenticated: false,
					user: null,
				}));
			}
		} catch (error) {
			console.error(error);
		}
	};

	useEffect(() => {
		getUser();
	}, []);

	// ✅ FIX: Memoize the value to keep it referentially stable
	const value = useMemo(
		() => ({
			isAuthenticated,
			isLoading,
			user,
			refresh: getUser,
			signOut,
		}),
		[isAuthenticated, isLoading, user, getUser, signOut],
	);

	return <UserContext.Provider value={value}>{children}</UserContext.Provider>;
};

export function useUser() {
	const context = useContext(UserContext);
	if (!context) {
		throw new Error('useUser must be used within a UserProvider');
	}
	return context;
}
